"// Recieve OpenSearch --> $client

const getAliases = async () => {
    const aliases = {};
    for (const name of ["utenti","utenti_incremental", "utenti_massive"]) {
        const response = await $client.indices.getAlias({ name }).catch(() => null);
        if (response) aliases[name] = Object.keys(response.body)[0];
    }
    return aliases;
}

  const aliases = await getAliases();
  const massiveIndex = aliases.utenti === "utenti_a" ? "utenti_b" : "utenti_a";

  // Delete the massive alias
  if (aliases.utenti_massive) {
    await $client.indices
      .deleteAlias({
        index: aliases.utenti_massive,
        name: "utenti_massive"
      })
      .catch(e => null);
  }

  // Delete Massive Index
  await $client.indices.delete({ index: massiveIndex }).catch(e => null);

  // Recreate the massive index
  await $client.indices.create({ index: massiveIndex });

  // Create the massive alias
  await $client.indices.putAlias({
    index: massiveIndex,
    name: "utenti_massive"
  });

  return "Start Check and Rotation Successful""

"// Receive OpenSearch --> $client

const getAliases = async () => {
    const aliases = {};
    for (const name of ["utenti", "utenti_incremental", "utenti_massive"]) {
        const response = await $client.indices.getAlias({ name }).catch(() => null);
        if (response) aliases[name] = Object.keys(response.body)[0];
    }
    return aliases;
}

  const aliases = await getAliases();

  // Delete incremental alias
  if (aliases.utenti_incremental) {
    await $client.indices
      .deleteAlias({
        index: aliases.utenti_incremental,
        name: "utenti_incremental"
      })
      .catch(e => null);
  }

  // Create Incremental alias pointing to the massive index
  await $client.indices.putAlias({
    index: aliases.utenti_massive,
    name: "utenti_incremental"
  });

  // Delete utenti alias
  if (aliases.utenti) {
    await $client.indices
      .deleteAlias({
        index: aliases.utenti,
        name: "utenti"
      })
      .catch();
  }

  // Create utenti alias pointing to the massive index
  await $client.indices.putAlias({
    index: aliases.utenti_massive,
    name: "utenti"
  });"

